python.secure:
def search(query: str, current_tenant: str):
    # Scope filter at the vector-store layer; cross-tenant docs are
    # never even retrieved.
    docs = vec_db.query(
        query_text=query,
        n_results=10,
        where={"tenant_id": {"$eq": current_tenant}},
    )
    return llm.complete(prompt=f"Docs: {docs}. Q: {query}")

