async def answer_legal_question(q: str) -> dict:
    # Retrieve grounding sources; refuse if no relevant docs found.
    sources = await rag.query(q, threshold=0.7)
    if not sources:
        return {"answer": "I don't have authoritative sources for this. "
                          "Please consult a licensed attorney."}
    answer = llm.complete(
        prompt=f"Answer using ONLY these sources: {sources}. Cite each.",
    )
    return {"answer": answer, "sources": sources, "disclaimer": "..."}

